1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
62	const CURSED_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const FIRST_INSURANCE_RATE = 0.1;
66	const LOYALTY_DISCOUNT_RATE = 0.2;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const FOLLOWUP_DISCOUNT_RATE = 0.15;
69	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
70	  sword: 100,
71	  amulet: 60,
72	  staff: 80,
73	  potion: 40,
74	  rune: 25,
75	  moonstone: 25,
76	};
77	
78	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const insuranceValue = (item: Item): number =>
88	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
89	
90	const insuranceSum = (items: Item[]): number =>
91	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
92	
93	const basePremium = (item: Item): number =>
94	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
95	
96	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
97	
98	const groupByType = (items: Item[]): Map<string, Item[]> => {
99	  const groups = new Map<string, Item[]>();
100	  for (const item of items) {
101	    const existing = groups.get(item.type) ?? [];
102	    existing.push(item);
103	    groups.set(item.type, existing);
104	  }
105	  return groups;
106	};
107	
108	const sumBasePremiums = (items: Item[]): number =>
109	  items.reduce((sum, item) => sum + basePremium(item), 0);
110	
111	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
112	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
113	
114	const groupTotal = (type: string, group: Item[]): number =>
115	  isCompleteComponentBlock(type, group)
116	    ? COMPONENT_BLOCK_PRICE
117	    : sumBasePremiums(group);
118	
119	const policyBase = (items: Item[]): number =>
120	  Array.from(groupByType(items)).reduce(
121	    (sum, [type, group]) => sum + groupTotal(type, group),
122	    0,
123	  );
124	
125	const perItemSurcharge = (
126	  items: Item[],
127	  predicate: (item: Item) => boolean,
128	  rate: number,
129	): number =>
130	  items.reduce(
131	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
132	    0,
133	  );
134	
135	const isCursed = (item: Item): boolean => item.cursed === true;
136	
137	const isHighlyEnchanted = (item: Item): boolean =>
138	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
139	
140	const firstInsuranceSurcharge = (base: number): number =>
141	  base * FIRST_INSURANCE_RATE;
142	
143	const loyaltyDiscount = (base: number, customer: Customer): number =>
144	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
145	    ? base * LOYALTY_DISCOUNT_RATE
146	    : 0;
147	
148	const followupDiscount = (base: number, quoteIndex: number): number =>
149	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
150	
151	const quotePremium = (
152	  items: Item[],
153	  customer: Customer,
154	  quoteIndex: number,
155	): number => {
156	  const base = policyBase(items);
157	  const modifiedBase =
158	    base +
159	    perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
160	    perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
161	    firstInsuranceSurcharge(base) -
162	    loyaltyDiscount(base, customer) -
163	    followupDiscount(base, quoteIndex);
164	  return Math.ceil(modifiedBase) + PROCESSING_FEE;
165	};
166	
167	interface Policy {
168	  items: Item[];
169	  remainingCap: number;
170	}
171	
172	interface ScenarioState {
173	  customer: Customer;
174	  policies: Map<number, Policy>;
175	  quoteIndex: number;
176	  stepIndex: number;
177	}
178	
179	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
180	  state.policies.set(state.stepIndex, {
181	    items: step.items,
182	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
183	  });
184	  return {
185	    premium: quotePremium(step.items, state.customer, state.quoteIndex),
186	  };
187	};
188	
189	const damagePayout = (damage: Damage, items: Item[]): number => {
190	  const item = items.find((it) => it.type === damage.itemType) as Item;
191	  const reimbursable =
192	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
193	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
194	      : damage.amount;
195	  return reimbursable - DEDUCTIBLE;
196	};
197	
198	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
199	  const policy = state.policies.get(step.policy) as Policy;
200	  const payout = step.incident.damages.reduce(
201	    (sum, damage) => sum + damagePayout(damage, policy.items),
202	    0,
203	  );
204	  policy.remainingCap -= payout;
205	  return { payout, remainingCap: policy.remainingCap };
206	};
207	
208	const processStep = (step: Step, state: ScenarioState): StepResult =>
209	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
210	
211	const quoteIndexAt = (steps: Step[], stepIndex: number): number =>
212	  steps.slice(0, stepIndex).filter((s) => s.op === "quote").length;
213	
214	export const processScenario = (scenario: Scenario): ScenarioOutput => {
215	  const policies = new Map<number, Policy>();
216	  const results: StepResult[] = scenario.steps.map((step, stepIndex) =>
217	    processStep(step, {
218	      customer: scenario.customer,
219	      policies,
220	      quoteIndex: quoteIndexAt(scenario.steps, stepIndex),
221	      stepIndex,
222	    }),
223	  );
224	  return { results };
225	};
